#nullable enable // autogenerated

using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Entities;
using MVZ2Logic.Artifacts;
using MVZ2Logic.Definitions;
using MVZ2Logic.Entities;
using MVZ2Logic.Level;
using PVZEngine;
using PVZEngine.Entities;
using PVZEngine.Level;

namespace MVZ2.GameContent.Artifacts
{
    [AutoArtifactDefinition(VanillaArtifactNames.censerOfForgotten)]
    public class CenserOfForgotten : ArtifactDefinition
    {
        public CenserOfForgotten(string nsp, string name) : base(nsp, name)
        {
        }
        public override void PostAdd(Artifact artifact)
        {
            base.PostAdd(artifact);
            artifact.SetNumber(MAX_COOLDOWN_SECONDS);
            artifact.SetSecondTimer(TimerHelper.NewSecondTimer(1));
        }
        public override void PostUpdate(Artifact artifact)
        {
            base.PostUpdate(artifact);
            var secondTimer = artifact.GetSecondTimer();
            if (secondTimer == null)
            {
                secondTimer = TimerHelper.NewSecondTimer(1);
                artifact.SetSecondTimer(secondTimer);
            }

            if (secondTimer.RunToExpired())
            {
                var number = artifact.GetNumber();
                number--;
                if (number <= 0)
                {
                    number = MAX_COOLDOWN_SECONDS;
                    Stun(artifact.Level);
                    artifact.Highlight();
                }
                artifact.SetNumber(number);
                secondTimer.Reset();
            }
        }
        public static void Stun(LevelEngine level)
        {
            bool stunned = false;
            foreach (var enemy in level.FindEntities(e => e.IsHostileEntity() && e.Type == EntityTypes.ENEMY && e.CanDeactive()))
            {
                enemy.Stun(Ticks.FromSeconds(STUN_SECONDS));
                stunned = true;
            }
            if (stunned)
            {
                level.PlaySound(VanillaSoundID.stunned);
            }
        }
        public const int MAX_COOLDOWN_SECONDS = 60;
        public const float STUN_SECONDS = 5;
    }
}
